import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import api from '../services/api';
import TTLogo from '../components/TTLogo';
import { Moon, User, Lock, EyeOff, AlertCircle } from 'lucide-react';

const Login: React.FC = () => {
  const [username, setUsername] = useState('admin');
  const [password, setPassword] = useState('Password123#');
  const [error, setError] = useState('Identifiants invalides'); // Default to show the UI from screenshot
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const res = await api.post('/auth/login', { username, password });
      login(res.data.token, res.data.user);
      navigate('/dashboard');
    } catch (err: any) {
      setError(err.response?.data?.message || 'Identifiants invalides');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex min-h-screen relative" style={{ background: 'linear-gradient(135deg, #fdfbfb 0%, #f4f7fe 100%)' }}>
      <div className="absolute top-6 right-8">
         <button className="h-10 w-10 flex items-center justify-center rounded-full bg-white shadow-sm border border-gray-100 text-gray-400 hover:text-gray-600">
           <Moon className="h-5 w-5" />
         </button>
      </div>

      <div className="m-auto w-full max-w-md">
        <div className="rounded-3xl bg-white p-8 shadow-[0_8px_30px_rgb(0,0,0,0.04)] sm:p-10 border border-gray-50 flex flex-col items-center">

          <TTLogo className="h-14 w-14 mb-4" />
          <h2 className="text-xl font-bold text-gray-900 tracking-tight">TT SecureWatch</h2>
          <p className="text-sm font-semibold text-gray-400 mb-8 tracking-wide">Portail Sécurisé Tunisie Telecom</p>

          <div className="flex w-full rounded-lg bg-gray-50 p-1 mb-6">
            <button className="flex-1 rounded-md bg-white py-2.5 text-xs font-bold text-primary shadow-sm">
              CONNEXION
            </button>
            <button className="flex-1 rounded-md py-2.5 text-xs font-bold text-gray-400 hover:text-gray-600 transition-colors">
              CRÉER UN COMPTE
            </button>
          </div>

          <form className="w-full space-y-5" onSubmit={handleLogin}>
            {error && (
              <div className="flex items-center rounded-lg bg-red-50 p-3 text-red-500 border border-red-100">
                <AlertCircle className="mr-2 h-4 w-4 flex-shrink-0" />
                <span className="text-xs font-medium">{error}</span>
              </div>
            )}

            <div className="space-y-1.5">
              <label className="text-xs font-bold uppercase tracking-wider text-gray-500 block">Nom d'utilisateur</label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 flex items-center pl-3.5 pointer-events-none">
                  <User className="h-4 w-4 text-gray-400" />
                </div>
                <input
                  type="text"
                  required
                  className="block w-full rounded-xl border border-blue-100 bg-blue-50/50 py-3 pl-10 pr-4 text-sm font-medium text-gray-900 focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary transition-colors"
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                />
              </div>
            </div>

            <div className="space-y-1.5">
              <label className="text-xs font-bold uppercase tracking-wider text-gray-500 block">Mot de passe</label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 flex items-center pl-3.5 pointer-events-none">
                  <Lock className="h-4 w-4 text-gray-400" />
                </div>
                <input
                  type="password"
                  required
                  className="block w-full rounded-xl border border-gray-200 bg-white py-3 pl-10 pr-10 text-sm font-medium text-gray-900 focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary transition-colors"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                />
                <div className="absolute inset-y-0 right-0 flex items-center pr-3.5 cursor-pointer">
                  <EyeOff className="h-4 w-4 text-gray-400 hover:text-gray-600" />
                </div>
              </div>
            </div>

            <button
              type="submit"
              disabled={loading}
              className="mt-4 w-full rounded-xl bg-[#1875c7] py-3.5 text-sm font-bold text-white shadow-md hover:bg-[#1560a6] hover:shadow-lg focus:outline-none focus:ring-2 focus:ring-primary focus:ring-offset-2 transition-all disabled:opacity-70"
            >
              {loading ? 'Connexion en cours...' : 'Se Connecter'}
            </button>
          </form>

          <div className="mt-8 text-center text-[10px] font-semibold tracking-wide text-gray-400">
            © 2026 Tunisie Telecom. Tous droits réservés.
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
